define([
    'core/ajax',
    'core/notification'
], function(Ajax, Notification) {

    const ChatBot = {

        state: {
            sessionId: null,
            courseId: 0,
            sessions: [],
            // messages: {},
            // activeMessages: [],
            isStreaming: false,
            controller: null,
            shouldAutoScroll: true,
        },

        init(sessionId, courseId) {
            this.state.sessionId = sessionId;
            this.state.courseId = courseId || 0;

            this.initMarkdown();
            this.bindUI();
            this.bindSessions();
            this.bindNewSession();
            this.bindDropdowns();
            this.scrollToBottom();
            this.bindArchive();
            this.bindCoursePicker();
            this.bindLanguagePicker();
            this.updateCoursePickerLock();

            if (sessionId) {
                const activeItem = document.querySelector(`.ai-session-item[data-session-id="${sessionId}"]`);
                this.setActiveLanguage(activeItem?.dataset.language || '');
            }


            const container = document.getElementById('ai-messages-container');

            container.addEventListener('scroll', () => {
                const nearBottom =
                    container.scrollHeight - container.scrollTop - container.clientHeight < 50;

                this.shouldAutoScroll = nearBottom;
            });

            // Any link inside a chat message (e.g. a course citation link
            // rendered from markdown) should open in a new tab instead of
            // navigating away from / inside the chat widget itself.
            // Delegated on the container (not on individual links) because
            // messages are inserted into the DOM dynamically — both from
            // streaming responses and from history loaded via AJAX — so a
            // one-time querySelectorAll pass at init time would miss every
            // link added afterwards.
            container.addEventListener('click', (e) => {
                const link = e.target.closest('a');
                if (!link || !container.contains(link)) return;

                e.preventDefault();
                window.open(link.href, '_blank', 'noopener,noreferrer');
            });
        },

        // =========================
        // COURSE PICKER
        // =========================
        bindCoursePicker() {
            const toggle = document.getElementById('ai-course-toggle');
            const dropdown = document.getElementById('ai-course-dropdown');
            const currentLabel = document.getElementById('ai-course-current-label');

            if (!toggle || !dropdown) return;

            toggle.addEventListener('click', (e) => {
                e.stopPropagation();
                toggle.classList.toggle('open');
                dropdown.classList.toggle('hidden');
            });

            document.addEventListener('click', () => {
                dropdown.classList.add('hidden');
                toggle.classList.remove('open');
            });

            const options = dropdown.querySelectorAll('.ai-course-option');

            options.forEach(option => {
                // pre-select "All my courses" by default
                if (option.dataset.courseId === '0') {
                    option.classList.add('selected');
                }

                option.addEventListener('click', (e) => {
                    e.stopPropagation();

                    const courseId = parseInt(option.dataset.courseId, 10) || 0;
                    this.state.courseId = courseId;

                    options.forEach(o => o.classList.remove('selected'));
                    option.classList.add('selected');

                    if (currentLabel) {
                        currentLabel.textContent = option.querySelector('.ai-course-option-label').textContent.trim();
                    }

                    dropdown.classList.add('hidden');
                    toggle.classList.remove('open');
                });
            });
        },

        // =========================
        // LANGUAGE PICKER
        // =========================
        bindLanguagePicker() {
            const toggle = document.getElementById('ai-language-toggle');
            const dropdown = document.getElementById('ai-language-dropdown');
            const currentLabel = document.getElementById('ai-language-current-label');

            if (!toggle || !dropdown) return;

            toggle.addEventListener('click', (e) => {
                e.stopPropagation();
                toggle.classList.toggle('open');
                dropdown.classList.toggle('hidden');
            });

            document.addEventListener('click', () => {
                dropdown.classList.add('hidden');
                toggle.classList.remove('open');
            });

            const options = dropdown.querySelectorAll('.ai-language-option');

            options.forEach(option => {
                option.addEventListener('click', async (e) => {
                    e.stopPropagation();

                    if (!this.state.sessionId || this.state.isTranslating) {   // CHANGED: +guard от повторного клика
                        dropdown.classList.add('hidden');
                        toggle.classList.remove('open');
                        return;
                    }

                    const language = option.dataset.language || '';
                    const isReset = language === '';

                    dropdown.classList.add('hidden');
                    toggle.classList.remove('open');

                    this.state.isTranslating = true;
                    this.showTranslatingOverlay(isReset);

                    try {
                        await Ajax.call([{
                            methodname: 'local_ai_system_update_session',
                            args: { session_id: this.state.sessionId, language }
                        }])[0];

                        this.setActiveLanguage(language);

                        const result = await Ajax.call([{
                            methodname: 'local_ai_system_get_messages',
                            args: { session_id: this.state.sessionId }
                        }])[0];

                        const container = document.getElementById('ai-messages-container');
                        container.innerHTML = '';

                        const messages = Array.isArray(result) ? result : (result.messages ?? []);
                        messages.forEach(msg => this.appendMessage(msg.role, msg.content));

                        const item = document.querySelector(`.ai-session-item[data-session-id="${this.state.sessionId}"]`);
                        if (item) {
                            item.dataset.language = language;
                            const badge = item.querySelector('.ai-session-lang-badge');
                            if (badge) {
                                badge.dataset.language = language;
                                badge.textContent = language;
                            }
                        }
                    } finally {
                        this.state.isTranslating = false;
                        this.hideTranslatingOverlay();
                    }
                });
            });
        },

        setActiveLanguage(language) {
            const dropdown = document.getElementById('ai-language-dropdown');
            const currentLabel = document.getElementById('ai-language-current-label');
            if (!dropdown || !currentLabel) return;

            const options = dropdown.querySelectorAll('.ai-language-option');
            options.forEach(o => o.classList.remove('selected'));

            const target = dropdown.querySelector(`.ai-language-option[data-language="${language || ''}"]`);
            if (target) {
                target.classList.add('selected');
                currentLabel.textContent = target.querySelector('.ai-language-option-label').textContent.trim();
            }
        },

        applyGeneratedTitle(title) {
            if (!title || !this.state.sessionId) return;

            const chatTitle = document.getElementById('ai-chat-title');
            if (chatTitle) chatTitle.textContent = title;

            const sidebarTitleEl = document.querySelector(
                `.ai-session-item[data-session-id="${this.state.sessionId}"] .ai-session-title`
            );
            if (sidebarTitleEl) sidebarTitleEl.textContent = title;
        },

        updateCoursePickerLock() {
            const toggle = document.getElementById('ai-course-toggle');
            if (!toggle) return;

            const locked = !!this.state.sessionId;
            toggle.classList.toggle('disabled', locked);
        },

        showTranslatingOverlay(isReset) {
            const overlay = document.getElementById('ai-translating-overlay');
            const label = document.getElementById('ai-translating-label');
            if (!overlay || !label) return;

            label.textContent = isReset ? overlay.dataset.labelLoading : overlay.dataset.labelTranslating;
            overlay.classList.remove('hidden');
        },

        hideTranslatingOverlay() {
            const overlay = document.getElementById('ai-translating-overlay');
            if (overlay) overlay.classList.add('hidden');
        },

        bindArchive() {
            const toggle = document.getElementById('ai-archive-toggle');
            const dropdown = document.getElementById('ai-archive-dropdown');
            if (!toggle || !dropdown) return;

            toggle.addEventListener('click', () => {
                toggle.classList.toggle('open');
                dropdown.classList.toggle('hidden');
            });

            // клик на архивный чат — только просмотр, без возможности писать
            document.querySelectorAll('.ai-session-archived').forEach(el => {
                el.addEventListener('click', async (e) => {
                    if (e.target.closest('.ai-session-menu-btn') || e.target.closest('.ai-session-dropdown')) return;

                    const sessionId = el.dataset.sessionId;
                    const title = el.querySelector('.ai-session-title').textContent.trim();
                    this.setActiveLanguage(el.dataset.language || '');

                    const result = await Ajax.call([{
                        methodname: 'local_ai_system_get_messages',
                        args: { session_id: sessionId }
                    }])[0];

                    const container = document.getElementById('ai-messages-container');
                    container.innerHTML = '';

                    const messages = Array.isArray(result) ? result : (result.messages ?? []);
                    messages.forEach(msg => this.appendMessage(msg.role, msg.content));

                    // заголовок с пометкой архива
                    const chatTitle = document.getElementById('ai-chat-title');
                    if (chatTitle) chatTitle.textContent = `${title} (archived)`;

                    // блокируем инпут
                    const input = document.getElementById('ai-message-input');
                    const sendBtn = document.getElementById('ai-send-btn');
                    if (input) { input.disabled = true; input.placeholder = 'Unarchive to send messages'; }
                    if (sendBtn) sendBtn.disabled = true;

                    this.state.sessionId = null; // не даём отправлять сообщения
                });
            });

            // дезархивация
            document.querySelectorAll('.ai-action-dearchive').forEach(el => {
                el.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const sessionId = el.dataset.sessionId;
                    document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                    await Ajax.call([{
                        methodname: 'local_ai_system_dearchive_session',
                        args: { session_id: sessionId }
                    }])[0];

                    // перезагружаем страницу чтобы обновить списки
                    window.location.reload();
                });
            });
        },

        bindDropdowns() {
            document.querySelectorAll('.ai-session-menu-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const sessionId = btn.dataset.sessionId;

                    document.querySelectorAll('.ai-session-dropdown').forEach(d => {
                        if (d.dataset.sessionId !== sessionId) d.classList.add('hidden');
                    });

                    const dropdown = document.querySelector(
                        `.ai-session-dropdown[data-session-id="${sessionId}"]`
                    );
                    dropdown.classList.toggle('hidden');
                });
            });

            document.addEventListener('click', () => {
                document.querySelectorAll('.ai-session-dropdown')
                    .forEach(d => d.classList.add('hidden'));
            });

            // ARCHIVE
            document.querySelectorAll('.ai-action-archive').forEach(el => {
                el.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const sessionId = el.dataset.sessionId;
                    document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                    await Ajax.call([{
                        methodname: 'local_ai_system_archive_session',
                        args: { session_id: sessionId }
                    }])[0];

                    const item = document.querySelector(`.ai-session-item[data-session-id="${sessionId}"]`);
                    const title = item?.querySelector('.ai-session-title')?.textContent.trim() ?? 'Chat';
                    const language = item?.dataset.language || '';        // NEW
                    if (item) item.remove();

                    this.addSessionToArchive(sessionId, title, language);  // CHANGED

                    if (this.state.sessionId === sessionId) {
                        this.state.sessionId = null;
                        document.getElementById('ai-messages-container').innerHTML = '';
                        const chatTitle = document.getElementById('ai-chat-title');
                        if (chatTitle) chatTitle.textContent = 'SDG-Campus AI Chatbot';
                    }
                });
            });

            // RENAME
            document.querySelectorAll('.ai-action-rename').forEach(el => {
                el.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const sessionId = el.dataset.sessionId;
                    document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                    const popup = document.getElementById('ai-rename-popup');
                    popup.classList.remove('hidden');
                    popup.dataset.sessionId = sessionId;
                    document.getElementById('ai-rename-input').value = '';
                    document.getElementById('ai-rename-input').focus();
                });
            });

            // DELETE
            document.querySelectorAll('.ai-action-delete').forEach(el => {
                el.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const sessionId = el.dataset.sessionId;
                    document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                    if (!confirm('Delete this chat?')) return;

                    await Ajax.call([{
                        methodname: 'local_ai_system_delete_session',
                        args: { session_id: sessionId }
                    }])[0];

                    // убираем из сайдбара
                    const item = document.querySelector(`.ai-session-item[data-session-id="${sessionId}"]`);
                    if (item) item.remove();

                    // если это активный чат — сбрасываем
                    if (this.state.sessionId === sessionId) {
                        this.state.sessionId = null;
                        document.getElementById('ai-messages-container').innerHTML = '';
                        const chatTitle = document.getElementById('ai-chat-title');
                        if (chatTitle) chatTitle.textContent = 'SDG-Campus AI Chatbot';
                    }
                });
            });

            // RENAME POPUP SAVE/CANCEL
            document.getElementById('ai-rename-save')?.addEventListener('click', async () => {
                const popup = document.getElementById('ai-rename-popup');
                const sessionId = popup.dataset.sessionId;
                const title = document.getElementById('ai-rename-input').value.trim();
                if (!title) return;

                await Ajax.call([{
                    methodname: 'local_ai_system_update_session',
                    args: { session_id: sessionId, title }
                }])[0];

                const el = document.querySelector(`.ai-session-item[data-session-id="${sessionId}"] .ai-session-title`);
                if (el) el.textContent = title;

                // обновить заголовок чата если это активный
                if (this.state.sessionId === sessionId) {
                    const chatTitle = document.getElementById('ai-chat-title');
                    if (chatTitle) chatTitle.textContent = title;
                }

                popup.classList.add('hidden');
            });

            document.getElementById('ai-rename-cancel')?.addEventListener('click', () => {
                document.getElementById('ai-rename-popup').classList.add('hidden');
            });
        },

        formatTime(date) {
            const h = date.getHours();
            const m = date.getMinutes().toString().padStart(2, '0');
            return `${h}:${m}`;
        },

        addSessionToArchive(sessionId, title, language = '') {   // CHANGED: добавлен language
            const dropdown = document.getElementById('ai-archive-dropdown');
            if (!dropdown) return;

            const empty = dropdown.querySelector('.ai-archive-empty');
            if (empty) empty.remove();

            const el = document.createElement('div');
            el.className = 'ai-session-item ai-session-archived';
            el.dataset.sessionId = sessionId;
            el.dataset.language = language;                        // NEW

            el.innerHTML = `
                <span class="ai-session-lang-badge" data-language="${language}"></span>
                <span class="ai-session-title">${title}</span>
                <button class="ai-session-menu-btn" data-session-id="${sessionId}" aria-label="Session menu">
                    <i class="fa fa-ellipsis-v"></i>
                </button>
                <div class="ai-session-dropdown hidden" data-session-id="${sessionId}">
                    <div class="ai-dropdown-item ai-action-dearchive" data-session-id="${sessionId}">
                        <i class="fa fa-inbox"></i> Unarchive
                    </div>
                    <div class="ai-dropdown-item ai-dropdown-danger ai-action-delete" data-session-id="${sessionId}">
                        <i class="fa fa-trash"></i> Delete
                    </div>
                </div>
            `;

            dropdown.prepend(el);

            // клик — открыть чат в режиме просмотра
            el.addEventListener('click', async (e) => {
                if (e.target.closest('.ai-session-menu-btn') || e.target.closest('.ai-session-dropdown')) return;  // MOVED вверх

                this.setActiveLanguage(el.dataset.language || '');   // MOVED после guard'а

                const result = await Ajax.call([{
                    methodname: 'local_ai_system_get_messages',
                    args: { session_id: sessionId }
                }])[0];

                const container = document.getElementById('ai-messages-container');
                container.innerHTML = '';

                const messages = Array.isArray(result) ? result : (result.messages ?? []);
                messages.forEach(msg => this.appendMessage(msg.role, msg.content));

                const chatTitle = document.getElementById('ai-chat-title');
                if (chatTitle) chatTitle.textContent = `${title} (archived)`;

                const input = document.getElementById('ai-message-input');
                const sendBtn = document.getElementById('ai-send-btn');
                if (input) { input.disabled = true; input.placeholder = 'Unarchive to send messages'; }
                if (sendBtn) sendBtn.disabled = true;

                this.state.sessionId = null;
            });

            el.querySelector('.ai-session-menu-btn').addEventListener('click', (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown')
                    .forEach(d => d.dataset.sessionId !== sessionId && d.classList.add('hidden'));
                el.querySelector('.ai-session-dropdown').classList.toggle('hidden');
            });

            // Dearchive
            el.querySelector('.ai-action-dearchive').addEventListener('click', async (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                await Ajax.call([{
                    methodname: 'local_ai_system_dearchive_session',
                    args: { session_id: sessionId }
                }])[0];

                el.remove();
                this.addSessionToSidebar(sessionId, title, el.dataset.language || '');   // CHANGED: прокидываем язык

                const input = document.getElementById('ai-message-input');
                const sendBtn = document.getElementById('ai-send-btn');
                if (input) { input.disabled = false; input.placeholder = 'Type your message...'; }
                if (sendBtn) sendBtn.disabled = false;
            });

            // Delete — без изменений
            el.querySelector('.ai-action-delete').addEventListener('click', async (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                if (!confirm('Delete this chat?')) return;

                await Ajax.call([{
                    methodname: 'local_ai_system_delete_session',
                    args: { session_id: sessionId }
                }])[0];

                el.remove();
            });
        },

        addSessionToSidebar(sessionId, title, language = '') {
            const list = document.querySelector('.ai-sb-chats');
            if (!list) return;

            document.querySelectorAll('.ai-session-item')
                .forEach(e => e.classList.remove('active'));

            const el = document.createElement('div');
            el.className = 'ai-session-item active';
            el.dataset.sessionId = sessionId;
            el.dataset.language = language;

            el.innerHTML = `
                <span class="ai-session-lang-badge" data-language="${language}"></span>
                <span class="ai-session-title">${title}</span>
                <button class="ai-session-menu-btn" data-session-id="${sessionId}" aria-label="Session menu">
                    <i class="fa fa-ellipsis-v"></i>
                </button>
                <div class="ai-session-dropdown hidden" data-session-id="${sessionId}">
                    <div class="ai-dropdown-item ai-action-archive" data-session-id="${sessionId}">
                        <i class="fa fa-archive"></i> Archive
                    </div>
                    <div class="ai-dropdown-item ai-action-rename" data-session-id="${sessionId}">
                        <i class="fa fa-pencil"></i> Rename
                    </div>
                    <div class="ai-dropdown-item ai-dropdown-danger ai-action-delete" data-session-id="${sessionId}">
                        <i class="fa fa-trash"></i> Delete
                    </div>
                </div>
            `;

            list.prepend(el);

            el.addEventListener('click', async (e) => {
                if (e.target.closest('.ai-session-menu-btn') || e.target.closest('.ai-session-dropdown')) return;

                const chatTitle = document.getElementById('ai-chat-title');
                if (chatTitle) chatTitle.textContent = title;

                const result = await Ajax.call([{
                    methodname: 'local_ai_system_get_messages',
                    args: { session_id: sessionId }
                }])[0];

                this.state.sessionId = sessionId;
                this.setActiveLanguage(el.dataset.language || '');   // CHANGED: было жёстко '', теперь читает реальный язык

                const container = document.getElementById('ai-messages-container');
                container.innerHTML = '';

                const messages = Array.isArray(result) ? result : (result.messages ?? []);
                messages.forEach(msg => this.appendMessage(msg.role, msg.content));

                document.querySelectorAll('.ai-session-item')
                    .forEach(e => e.classList.remove('active'));
                el.classList.add('active');
            });

            // кнопка меню
            el.querySelector('.ai-session-menu-btn').addEventListener('click', (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown')
                    .forEach(d => d.dataset.sessionId !== sessionId && d.classList.add('hidden'));
                el.querySelector('.ai-session-dropdown').classList.toggle('hidden');
            });

            // Archive
            el.querySelector('.ai-action-archive').addEventListener('click', async (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                await Ajax.call([{
                    methodname: 'local_ai_system_archive_session',
                    args: { session_id: sessionId }
                }])[0];

                el.remove();
                this.addSessionToArchive(sessionId, title, el.dataset.language || '');  // CHANGED: прокидываем язык

                if (this.state.sessionId === sessionId) {
                    this.state.sessionId = null;
                    document.getElementById('ai-messages-container').innerHTML = '';
                    const chatTitle = document.getElementById('ai-chat-title');
                    if (chatTitle) chatTitle.textContent = 'SDG-Campus AI Chatbot';
                }
            });

            // Rename
            el.querySelector('.ai-action-rename').addEventListener('click', (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                const popup = document.getElementById('ai-rename-popup');
                popup.classList.remove('hidden');
                popup.dataset.sessionId = sessionId;
                document.getElementById('ai-rename-input').value = '';
                document.getElementById('ai-rename-input').focus();
            });

            // Delete
            el.querySelector('.ai-action-delete').addEventListener('click', async (e) => {
                e.stopPropagation();
                document.querySelectorAll('.ai-session-dropdown').forEach(d => d.classList.add('hidden'));

                if (!confirm('Delete this chat?')) return;

                await Ajax.call([{
                    methodname: 'local_ai_system_delete_session',
                    args: { session_id: sessionId }
                }])[0];

                el.remove();

                if (this.state.sessionId === sessionId) {
                    this.state.sessionId = null;
                    document.getElementById('ai-messages-container').innerHTML = '';
                    const chatTitle = document.getElementById('ai-chat-title');
                    if (chatTitle) chatTitle.textContent = 'SDG-Campus AI Chatbot';
                }
            });
        },

        // for messages
        async ensureSession() {
            if (this.state.sessionId) {
                return this.state.sessionId;
            }

            try {
                const result = await Ajax.call([{
                    methodname: 'local_ai_system_create_session',
                    args: {
                        course_id: this.state.courseId
                    }
                }])[0];

                this.state.sessionId = result.session_id;
                this.addSessionToSidebar(result.session_id, result.title || 'New Chat', '');
                this.updateCoursePickerLock();

                return this.state.sessionId;

            } catch (e) {
                console.error('ensureSession failed:', e);
                return null;
            }
        },

        // for new chat button
        async createNewSession() {
            const sessionNumber = document.querySelectorAll('.ai-session-item').length + 1;
            const title = `New Chat ${sessionNumber}`;

            const result = await Ajax.call([{
                methodname: 'local_ai_system_create_session',
                args: {
                    title: `New Chat ${sessionNumber}`,
                    course_id: this.state.courseId
                }
            }])[0];

            this.state.sessionId = result.session_id;

            this.addSessionToSidebar(result.session_id, `New Chat ${sessionNumber}`);

            return { sessionId: result.session_id, title };
        },

        scrollToBottom() {
            if (!this.shouldAutoScroll) return;

            const container = document.getElementById('ai-messages-container');
            container.scrollTop = container.scrollHeight;
        },

        // =========================
        // MARKDOWN
        // =========================
        initMarkdown() {
            if (window.marked) {
                window.marked.setOptions({
                    breaks: true,
                    gfm: true
                });
            }
        },


        updateUIState() {
            const input = document.getElementById('ai-message-input');
            const sendBtn = document.getElementById('ai-send-btn');
            // const stopBtn = document.getElementById('ai-stop-btn');

            const isStreaming = this.state.isStreaming;

            if (input) input.disabled = isStreaming;
            if (sendBtn) sendBtn.disabled = isStreaming;

            // if (stopBtn) {
            //     stopBtn.disabled = !isStreaming;
            // }
        },

        // =========================
        // UI BINDINGS
        // =========================
        bindUI() {
            const sendBtn = document.getElementById('ai-send-btn');
            const input = document.getElementById('ai-message-input');
            const stopBtn = document.getElementById('ai-stop-btn');

            const send = () => {
                const message = input.value.trim();
                if (!message) return;

                input.value = '';
                this.sendMessageStream(message);
            };

            sendBtn.addEventListener('click', () => {
                if (this.state.isStreaming) return;
                send();
            });

            input.addEventListener('keydown', (e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    if (this.state.isStreaming) return;
                    send();
                }
            });

            if (stopBtn) {
                stopBtn.addEventListener('click', () => {
                    if (this.state.controller) {
                        this.state.controller.abort();
                        this.state.isStreaming = false;
                        this.updateUIState();
                        document.getElementById('ai-send-btn').style.display = 'flex';
                        document.getElementById('ai-stop-btn').style.display = 'none';
                    }
                });
            }
        },

        // =========================
        // STREAM MESSAGE
        // =========================
        async sendMessageStream(message) {

            if (this.state.isStreaming) return;

            this.state.isStreaming = true;
            this.state.controller = new AbortController();
            this.updateUIState();

            document.getElementById('ai-send-btn').style.display = 'none';
            document.getElementById('ai-stop-btn').style.display = 'flex';

            this.appendMessage('user', message);

            const bubble = this.createAssistantBubble();
            let fullText = '';

            await this.ensureSession();

            try {
                const response = await fetch(
                    M.cfg.wwwroot + '/local/ai_system/ajax/stream.php',
                    {
                        method: 'POST',
                        signal: this.state.controller.signal,
                        headers: {
                            'Content-Type': 'application/x-www-form-urlencoded'
                        },
                        body: new URLSearchParams({
                            session_id: this.state.sessionId,
                            message: message
                        })
                    }
                );

                const reader = response.body.getReader();
                const decoder = new TextDecoder('utf-8');

                let buffer = '';

                while (true) {
                    const { value, done } = await reader.read();
                    if (done) break;

                    const chunk = decoder.decode(value, { stream: true });

                    buffer += chunk;

                    const lines = buffer.split('\n');

                    buffer = lines.pop();
                    
                    for (let line of lines) {
                        line = line.trim();

                        if (!line.startsWith('data:')) continue;

                        const raw = line.replace(/^data:\s?/, '');

                        if (raw === '[DONE]') continue;

                        // Tokens are JSON-encoded server-side so a token
                        // containing a literal newline (extremely common —
                        // e.g. between list items or paragraphs) survives
                        // intact as an escaped "\n" instead of becoming a
                        // real line break that would split this SSE event
                        // across multiple physical lines and get partially
                        // dropped by the `if (!line.startsWith('data:'))`
                        // check above.
                        let parsed;
                        try {
                            parsed = JSON.parse(raw);
                        } catch (err) {
                            console.error('[ChatBot] Failed to parse SSE payload, skipping:', raw, err);
                            continue;
                        }

                        if (parsed.title !== undefined) {
                            this.applyGeneratedTitle(parsed.title);
                            continue;
                        }

                        const token = parsed.token;
                        fullText += token;

                        // Render markdown live, on every chunk, instead of
                        // only once at the very end — so bold/lists/links
                        // appear as the message is being typed, not after
                        // the fact. Partial markup (e.g. an unclosed "**")
                        // may render oddly for a split second until the
                        // closing token arrives — that's expected and
                        // self-corrects on the next chunk.
                        try {
                            bubble.innerHTML = window.marked ? window.marked.parse(fullText) : fullText;
                        } catch (err) {
                            bubble.innerText = fullText;
                        }

                        this.scrollToBottom();
                    }
                }
            } catch (e) {
                console.error(e);
                this.state.isStreaming = false;
                this.state.controller = null;
                this.updateUIState();
            } finally {
                this.state.isStreaming = false;
                this.state.controller = null;
                this.updateUIState();

                // If marked.parse throws (or window.marked isn't loaded
                // yet for some reason), fall back to plain text instead
                // of silently leaving the bubble unrendered — and log it,
                // so it's visible in devtools instead of failing quietly.
                try {
                    if (!window.marked) {
                        console.warn('[ChatBot] window.marked is not available yet — showing plain text.');
                        bubble.innerText = fullText;
                    } else {
                        bubble.innerHTML = window.marked.parse(fullText || '');
                    }
                } catch (err) {
                    console.error('[ChatBot] Failed to render markdown, showing plain text instead:', err);
                    bubble.innerText = fullText;
                }

                const timeEl = document.getElementById('ai-streaming-time');
                if (timeEl) {
                    timeEl.textContent = this.formatTime(new Date());
                    timeEl.removeAttribute('id');
                }
                
                document.getElementById('ai-send-btn').style.display = 'flex';
                document.getElementById('ai-stop-btn').style.display = 'none';
                
                this.scrollToBottom();
            }
        },

        // =========================
        // MESSAGES UI
        // =========================
        appendMessage(role, content) {

            const container = document.getElementById('ai-messages-container');

            const wrap = document.createElement('div');
            wrap.className = `ai-message ai-message--${role}`;

            const bubbleWrap = document.createElement('div');
            bubbleWrap.className = 'ai-bubble-wrap';

            const bubble = document.createElement('div');
            bubble.className = 'ai-message-bubble';

            const text = document.createElement('div');
            text.className = 'ai-message-content';
            text.innerHTML = window.marked.parse(content || '');

            const time = document.createElement('span');
            time.className = 'ai-message-time';
            time.textContent = this.formatTime(new Date());

            bubble.appendChild(text);
            bubbleWrap.appendChild(bubble);
            bubbleWrap.appendChild(time);
            wrap.appendChild(bubbleWrap);
            container.appendChild(wrap)

            this.scrollToBottom();
        },

        createAssistantBubble() {

            const container = document.getElementById('ai-messages-container');

            const wrap = document.createElement('div');
            wrap.className = 'ai-message ai-message--assistant';

            const bubbleWrap = document.createElement('div');
            bubbleWrap.className = 'ai-bubble-wrap';

            const bubble = document.createElement('div');
            bubble.className = 'ai-message-bubble';

            const text = document.createElement('div');
            text.className = 'ai-message-content';

            const time = document.createElement('span');
            time.className = 'ai-message-time';
            time.id = 'ai-streaming-time';

            bubble.appendChild(text);
            bubbleWrap.appendChild(bubble);
            bubbleWrap.appendChild(time);
            wrap.appendChild(bubbleWrap);
            container.appendChild(wrap);

            return text;
        },

        // =========================
        // SESSIONS
        // =========================
        bindSessions() {

            document.querySelectorAll('.ai-session-item').forEach(el => {

                el.addEventListener('click', async () => {
                    const input = document.getElementById('ai-message-input');
                    const sendBtn = document.getElementById('ai-send-btn');
                    if (input) { input.disabled = false; input.placeholder = 'Type your message...'; }
                    if (sendBtn) sendBtn.disabled = false;

                    const sessionId = el.dataset.sessionId;
                    this.setActiveLanguage(el.dataset.language || '');
                    const title = el.querySelector('.ai-session-title').textContent.trim();

                    const chatTitle = document.getElementById('ai-chat-title');
                    if (chatTitle) chatTitle.textContent = title;

                    const result = await Ajax.call([{
                        methodname: 'local_ai_system_get_messages',
                        args: { session_id: sessionId }
                    }])[0];

                    this.state.sessionId = sessionId;

                    const container = document.getElementById('ai-messages-container');
                    container.innerHTML = '';

                    const messages = Array.isArray(result) ? result : (result.messages ?? []);

                    messages.forEach(msg => {
                        this.appendMessage(msg.role, msg.content);  // content, не content_raw
                    });

                    document.querySelectorAll('.ai-session-item')
                        .forEach(e => e.classList.remove('active'));

                    el.classList.add('active');
                });
            });
        },

        // =========================
        // NEW SESSION
        // =========================
        bindNewSession() {

            const btn = document.querySelector('.ai-chatbot-new-session');

            if (!btn) return;

            btn.addEventListener('click', async () => {
                const { title } = await this.createNewSession();
                document.getElementById('ai-messages-container').innerHTML = '';

                const chatTitle = document.getElementById('ai-chat-title');
                if (chatTitle) chatTitle.textContent = title;
            });
        },
    };

    return {
        init: (sessionId, courseId) => ChatBot.init(sessionId, courseId)
    };
});
